const express = require('express');
const app = express();
const MongoClient = require('mongodb').MongoClient;

let db;

MongoClient.connect('mongodb://localhost:27017/admin_dashboard', { useUnifiedTopology: true }, (err, client) => {
  if (err) return console.error(err);
  db = client.db('admin_dashboard');
});

const queryBuilder = (filter, projection, sort) => {
  return new Promise((resolve, reject) => {
    db.collection('users').find(filter, { projection }).sort(sort).toArray((err, result) => {
      if (err) reject(err);
      resolve(result);
    });
  });
};

app.get('/users', async (req, res) => {
  try {
    const filter = req.query.filter ? JSON.parse(req.query.filter) : {};
    const projection = req.query.projection ? JSON.parse(req.query.projection) : {};
    const sort = req.query.sort ? JSON.parse(req.query.sort) : {};
    const users = await queryBuilder(filter, projection, sort);
    res.json(users);
  } catch (err) {
    res.status(500).json({ error: 'An error occurred while querying the database.' });
  }
});

app.listen(3000, () => console.log('Server is running on port 3000'));